function isPrime(n) {
  if (n <= 1) return false; // 0 and 1 are not prime
  for (let i = 2; i * i <= n; i++) {
    if (n % i === 0) return false; // if divisible by any number between 2 and sqrt(n), it's not prime
  }
  return true; // if no divisors found, it's a prime number
}

// Example usage:
